function checkSpec(metric, value, stage, product) {
  if (value == null) return null;
  const pspecs = SPECS[product];
  if (!pspecs) return null;
  const s = pspecs[metric];
  if (!s || !s.stages.includes(stage)) return null;
  if (s.maxOnly) return value > s.high ? 'HIGH' : 'OK';
  if (s.low != null && value < s.low) return 'LOW';
  if (s.high != null && value > s.high) return 'HIGH';
  return 'OK';
}

function computeOOS(readings, product) {
  const flags = [];
  const metrics = ['OG','Wort pH','IBU (W)','ABV','FG','IBU','Total VDK'];
  const pspecs = SPECS[product] || {};
  for (const r of readings) {
    for (const m of metrics) {
      const val = r[m];
      if (val == null) continue;
      const status = checkSpec(m, val, r.stage, product);
      if (status && status !== 'OK') {
        flags.push({ metric:m, value:val, status, spec:pspecs[m], date:r.date, sample:r.sample, stage:r.stage });
      }
    }
  }
  return flags;
}

